import{_ as a,o as l,c as r,a0 as o}from"./chunks/framework.Dx25mwie.js";const h=JSON.parse('{"title":"Claude 最佳实践","description":"","frontmatter":{"head":[]},"headers":[],"relativePath":"docs/0.overview/03-claude-best-practices.md","filePath":"cn/docs/0.overview/03-claude-best-practices.md"}'),t={name:"docs/0.overview/03-claude-best-practices.md"};function i(d,e,c,s,n,u){return l(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="claude-最佳实践" tabindex="-1">Claude 最佳实践 <a class="header-anchor" href="#claude-最佳实践" aria-label="Permalink to &quot;Claude 最佳实践&quot;">​</a></h1><p>沉淀在 Go-Spring 里和 Claude（及其它 AI 编码助手）协作的经验，按固化程度分两类：</p><ul><li><strong>硬约定</strong>：无需判断即可照做，维护在 <code>CLAUDE.md</code> / Skill / hooks 里自动生效。</li><li><strong>软约定</strong>：依赖判断、随场景变化，写死反而误伤，留在文档里供人参考。</li></ul><h2 id="硬约定" tabindex="-1">硬约定 <a class="header-anchor" href="#硬约定" aria-label="Permalink to &quot;硬约定&quot;">​</a></h2><p>已经固化的规则统一维护在根目录 <code>CLAUDE.md</code>：<a href="https://github.com/go-spring/go-spring/blob/master/CLAUDE.md" target="_blank" rel="noreferrer">go-spring/go-spring · CLAUDE.md</a>。</p><p>一条经验若“无需上下文、无需权衡，照做即可”，就沉淀到那里，并从软约定中移除。</p><h2 id="软约定" tabindex="-1">软约定 <a class="header-anchor" href="#软约定" aria-label="Permalink to &quot;软约定&quot;">​</a></h2><p>依赖判断、随场景变化的经验，刻意不固化成规则：</p><ul><li>拆 PR 还是合并成一个，看改动的内聚性，而非行数。</li><li>是否抽象：三行相似代码通常好过一个过早的抽象，收敛时机看具体情况。</li><li>先追问还是直接动手，看任务的模糊程度和可逆性。</li></ul><h2 id="维护约定" tabindex="-1">维护约定 <a class="header-anchor" href="#维护约定" aria-label="Permalink to &quot;维护约定&quot;">​</a></h2><ul><li>软约定尽量标注来源（哪次协作、什么问题触发），便于判断是否过时。</li><li>成熟、可机械执行的软约定，搬进 <code>CLAUDE.md</code> 或 Skill 后从本文档移除。</li><li>某条规则频繁误伤，就从 <code>CLAUDE.md</code> 降级回软约定，并记录原因。</li></ul>',11)])])}const _=a(t,[["render",i]]);export{h as __pageData,_ as default};
